  1	import * as React from 'react';
  2	import {
  3	  GetBucketLifecycleConfigurationCommandOutput,
  4	  Tag,
  5	} from '@aws-sdk/client-s3';
  6	import StaticDropdown from '@odf/shared/dropdown/StaticDropdown';
  7	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  8	import { dehumanize } from '@odf/shared/utils';
  9	import {
 10	  TextVariants,
 11	  Text,
 12	  TextContent,
 13	  Divider,
 14	  FormGroup,
 15	  TextInput,
 16	  Radio,
 17	  Alert,
 18	  AlertVariant,
 19	  ValidatedOptions,
 20	  Button,
 21	  ButtonVariant,
 22	  Checkbox,
 23	  NumberInput,
 24	  FormHelperText,
 25	  HelperText,
 26	  HelperTextItem,
 27	} from '@patternfly/react-core';
 28	import { TrashIcon, PlusCircleIcon } from '@patternfly/react-icons';
 29	import {
 30	  StateAndDispatchProps,
 31	  RuleState,
 32	  RuleActionType,
 33	  RuleScope,
 34	  ObjectSize,
 35	  SizeUnit,
 36	  FuncType,
 37	} from './reducer';
 38	import {
 39	  isInvalidName,
 40	  areInvalidFilters,
 41	  isInvalidObjectTag,
 42	  isInvalidObjectSize,
 43	} from './validations';
 44	import './create-lifecycle-rules.scss';
 45	
 46	const RADIO_GROUP_NAME = 'lifecycle-rule-scope-radio';
 47	const MAX_OBJ_SIZE = 'maxObjectSize';
 48	const MIN_OBJ_SIZE = 'minObjectSize';
 49	const UNITS_TYPE = 'binaryBytes';
 50	
 51	type TagField = keyof Tag;
 52	type SizeField = keyof Pick<
 53	  RuleState['conditionalFilters'],
 54	  typeof MAX_OBJ_SIZE | typeof MIN_OBJ_SIZE
 55	>;
 56	type SizeAction =
 57	  | RuleActionType.RULE_MAX_SIZE_FILTER
 58	  | RuleActionType.RULE_MIN_SIZE_FILTER;
 59	
 60	const getSizeObjAndActionType = (
 61	  sizeField: SizeField,
 62	  maxObjectSize: ObjectSize,
 63	  minObjectSize: ObjectSize
 64	): [ObjectSize, SizeAction] => [
 65	  sizeField === MAX_OBJ_SIZE ? maxObjectSize : minObjectSize,
 66	  sizeField === MAX_OBJ_SIZE
 67	    ? RuleActionType.RULE_MAX_SIZE_FILTER
 68	    : RuleActionType.RULE_MIN_SIZE_FILTER,
 69	];
 70	
 71	const ObjectSizeFilter: React.FC<StateAndDispatchProps> = ({
 72	  state,
 73	  dispatch,
 74	}) => {
 75	  const { t } = useCustomTranslation();
 76	
 77	  const minObjectSize = state.conditionalFilters.minObjectSize;
 78	  const maxObjectSize = state.conditionalFilters.maxObjectSize;
 79	  const onNumberInputAction = (
 80	    sizeField: SizeField,
 81	    funcType: FuncType,
 82	    event?: React.FormEvent<HTMLInputElement>
 83	  ) => {
 84	    const [objectSize, objectSizeAction] = getSizeObjAndActionType(
 85	      sizeField,
 86	      maxObjectSize,
 87	      minObjectSize
 88	    );
 89	    let newSize: number;
 90	    switch (funcType) {
 91	      case FuncType.ON_CHANGE: {
 92	        newSize = Math.max(+(event?.target as HTMLInputElement)?.value || 0, 0);
 93	        break;
 94	      }
 95	      case FuncType.ON_MINUS: {
 96	        newSize = Math.max(objectSize.size - 1, 0);
 97	        break;
 98	      }
 99	      case FuncType.ON_PLUS: {
100	        newSize = objectSize.size + 1;
101	        break;
102	      }
103	    }
104	    const newSizeInB: number = Math.round(
105	      dehumanize(`${newSize}${objectSize.unit}`, UNITS_TYPE).value
106	    );
107	    dispatch({
108	      type: objectSizeAction,
109	      payload: {
110	        ...objectSize,
111	        size: newSize,
112	        sizeInB: newSizeInB,
113	      },
114	    });
115	  };
116	  const onUnitDropdownChange = (sizeField: SizeField, newUnit: SizeUnit) => {
117	    const [objectSize, objectSizeAction] = getSizeObjAndActionType(
118	      sizeField,
119	      maxObjectSize,
120	      minObjectSize
121	    );
122	    const newSizeInB: number = Math.round(
123	      dehumanize(`${objectSize.size}${newUnit}`, UNITS_TYPE).value
124	    );
125	    dispatch({
126	      type: objectSizeAction,
127	      payload: {
128	        ...objectSize,
129	        unit: newUnit,
130	        sizeInB: newSizeInB,
131	      },
132	    });
133	  };
134	
135	  const [, invalidMinSize, invalidMaxSize, invalidSize] =
136	    state.triggerInlineValidations ? isInvalidObjectSize(state) : [];
137	
138	  return (
139	    <>
140	      <Checkbox
141	        id="min-object-size"
142	        label={t('Specify minimum object size')}
143	        isChecked={minObjectSize.isChecked}
144	        onChange={(_e, checked) =>
145	          dispatch({
146	            type: RuleActionType.RULE_MIN_SIZE_FILTER,
147	            payload: { ...minObjectSize, isChecked: checked },
148	          })
149	        }
150	        body={
151	          minObjectSize.isChecked ? (
152	            <>
153	              <span>
154	                <NumberInput
155	                  value={minObjectSize.size}
156	                  min={0}
157	                  onMinus={() =>
158	                    onNumberInputAction(MIN_OBJ_SIZE, FuncType.ON_MINUS)
159	                  }
160	                  onPlus={() =>
161	                    onNumberInputAction(MIN_OBJ_SIZE, FuncType.ON_PLUS)
162	                  }
163	                  onChange={(e) =>
164	                    onNumberInputAction(MIN_OBJ_SIZE, FuncType.ON_CHANGE, e)
165	                  }
166	                  className="pf-v6-u-mr-sm"
167	                  validated={
168	                    invalidMinSize
169	                      ? ValidatedOptions.error
170	                      : ValidatedOptions.default
171	                  }
172	                />
173	                <StaticDropdown
174	                  defaultSelection={minObjectSize.unit}
175	                  dropdownItems={SizeUnit}
176	                  onSelect={(newUnit: SizeUnit) =>
177	                    onUnitDropdownChange(MIN_OBJ_SIZE, newUnit)
178	                  }
179	                  className="pf-v6-u-mr-sm"
180	                />
181	                {t('{{sizeInB}} Bytes', { sizeInB: minObjectSize.sizeInB })}
182	              </span>
183	              {invalidMinSize && (
184	                <FormHelperText>
185	                  <HelperText>
186	                    <HelperTextItem variant={ValidatedOptions.error}>
187	                      {t('Must be a positive number 0 Byte or higher.')}
188	                    </HelperTextItem>
189	                  </HelperText>
190	                </FormHelperText>
191	              )}
192	            </>
193	          ) : null
194	        }
195	        className="pf-v6-u-mb-sm"
196	      />
197	      <Checkbox
198	        id="max-object-size"
199	        label={t('Specify maximum object size')}
200	        isChecked={maxObjectSize.isChecked}
201	        onChange={(_e, checked) =>
202	          dispatch({
203	            type: RuleActionType.RULE_MAX_SIZE_FILTER,
204	            payload: { ...maxObjectSize, isChecked: checked },
205	          })
206	        }
207	        body={
208	          maxObjectSize.isChecked ? (
209	            <>
210	              <span>
211	                <NumberInput
212	                  value={maxObjectSize.size}
213	                  min={0}
214	                  onMinus={() =>
215	                    onNumberInputAction(MAX_OBJ_SIZE, FuncType.ON_MINUS)
216	                  }
217	                  onPlus={() =>
218	                    onNumberInputAction(MAX_OBJ_SIZE, FuncType.ON_PLUS)
219	                  }
220	                  onChange={(e) =>
221	                    onNumberInputAction(MAX_OBJ_SIZE, FuncType.ON_CHANGE, e)
222	                  }
223	                  className="pf-v6-u-mr-sm"
224	                  validated={
225	                    invalidMaxSize || invalidSize
226	                      ? ValidatedOptions.error
227	                      : ValidatedOptions.default
228	                  }
229	                />
230	                <StaticDropdown
231	                  defaultSelection={maxObjectSize.unit}
232	                  dropdownItems={SizeUnit}
233	                  onSelect={(newUnit: SizeUnit) =>
234	                    onUnitDropdownChange(MAX_OBJ_SIZE, newUnit)
235	                  }
236	                  className="pf-v6-u-mr-sm"
237	                />
238	                {t('{{sizeInB}} Bytes', { sizeInB: maxObjectSize.sizeInB })}
239	              </span>
240	              {(invalidMaxSize || invalidSize) && (
241	                <FormHelperText>
242	                  <HelperText>
243	                    <HelperTextItem variant={ValidatedOptions.error}>
244	                      {invalidMaxSize &&
245	                        t('Must be a positive number 1 Byte or higher.')}
246	                      {invalidSize &&
247	                        t(
248	                          'The maximum object size must be larger than the minimum object size.'
249	                        )}
250	                    </HelperTextItem>
251	                  </HelperText>
252	                </FormHelperText>
253	              )}
254	            </>
255	          ) : null
256	        }
257	        className="pf-v6-u-mt-sm"
258	      />
259	    </>
260	  );
261	};
