263	const ObjectTagsFilter: React.FC<StateAndDispatchProps> = ({
264	  state,
265	  dispatch,
266	}) => {
267	  const { t } = useCustomTranslation();
268	
269	  const objectTags = state.conditionalFilters.objectTags;
270	  const onTagChange = (index: number, field: TagField, value: string) => {
271	    const newObjectTags = [...objectTags];
272	    newObjectTags[index][field] = value;
273	    dispatch({ type: RuleActionType.RULE_TAGS_FILTER, payload: newObjectTags });
274	  };
275	
276	  return (
277	    <>
278	      {objectTags.map((tag, index) => {
279	        const [invalidTag, emptyKey, alreadyUsedKey] =
280	          state.triggerInlineValidations
281	            ? isInvalidObjectTag(state, tag, index)
282	            : [];
283	
284	        return (
285	          <>
286	            <span
287	              key={index}
288	              className="pf-v6-u-display-flex pf-v6-u-flex-direction-row pf-v6-u-mb-xs"
289	            >
290	              <TextInput
291	                id="object-tags-key"
292	                value={tag.Key}
293	                onChange={(_e, value) => onTagChange(index, 'Key', value)}
294	                placeholder={t('Key')}
295	                className="pf-v6-u-mr-sm pf-v6-u-w-25"
296	                validated={
297	                  invalidTag ? ValidatedOptions.error : ValidatedOptions.default
298	                }
299	              />
300	              <TextInput
301	                id="object-tags-value"
302	                value={tag.Value}
303	                onChange={(_e, value) => onTagChange(index, 'Value', value)}
304	                placeholder={t('Value (Optional)')}
305	                className="pf-v6-u-mr-sm pf-v6-u-w-25"
306	              />
307	              <Button
308	                variant={ButtonVariant.plain}
309	                onClick={() =>
310	                  dispatch({
311	                    type: RuleActionType.RULE_TAGS_FILTER,
312	                    payload: objectTags.filter((_, i) => i !== index),
313	                  })
314	                }
315	              >
316	                <TrashIcon />
317	              </Button>
318	            </span>
319	            {invalidTag && (
320	              <FormHelperText>
321	                <HelperText>
322	                  <HelperTextItem variant={ValidatedOptions.error}>
323	                    {emptyKey && t('A tag key is required.')}
324	                    {alreadyUsedKey && t('Keys must be unique.')}
325	                  </HelperTextItem>
326	                </HelperText>
327	              </FormHelperText>
328	            )}
329	          </>
330	        );
331	      })}
332	      <Button
333	        variant={ButtonVariant.link}
334	        className="s3-lifecycle--margin"
335	        onClick={() =>
336	          dispatch({
337	            type: RuleActionType.RULE_TAGS_FILTER,
338	            payload: [...objectTags, { Key: '', Value: '' }],
339	          })
340	        }
341	      >
342	        <PlusCircleIcon /> {t('Add object tag')}
343	      </Button>
344	    </>
345	  );
346	};
347	
348	const ConditionalFilters: React.FC<StateAndDispatchProps> = ({
349	  state,
350	  dispatch,
351	}) => {
352	  const { t } = useCustomTranslation();
353	
354	  const invalidFilters =
355	    state.triggerInlineValidations && areInvalidFilters(state);
356	
357	  return (
358	    <>
359	      <TextContent className="pf-v6-u-mb-lg">
360	        <Text component={TextVariants.h2}>{t('Conditional filters')}</Text>
361	        <Text component={TextVariants.small}>
362	          {t(
363	            'Define specific criteria for selecting objects that the rules will apply to. Object tags or object size filters do not apply to incomplete multipart uploads or expired object delete markers.'
364	          )}
365	        </Text>
366	      </TextContent>
367	
368	      <FormGroup label={t('Prefix')} fieldId="prefix" className="pf-v6-u-mb-lg">
369	        <TextInput
370	          id="prefix"
371	          value={state.conditionalFilters.prefix}
372	          onChange={(_e, value) =>
373	            dispatch({
374	              type: RuleActionType.RULE_PREFIX_FILTER,
375	              payload: value,
376	            })
377	          }
378	          placeholder={t('Enter prefix')}
379	          className="pf-v6-u-w-50"
380	          validated={
381	            invalidFilters ? ValidatedOptions.error : ValidatedOptions.default
382	          }
383	        />
384	        {invalidFilters ? (
385	          <FormHelperText>
386	            <HelperText>
387	              <HelperTextItem variant={ValidatedOptions.error}>
388	                {t('You must specify a prefix or another filter.')}
389	              </HelperTextItem>
390	            </HelperText>
391	          </FormHelperText>
392	        ) : (
393	          <TextContent>
394	            <Text component={TextVariants.small}>
395	              {t('A prefix filters bucket objects by their keys.')}
396	            </Text>
397	          </TextContent>
398	        )}
399	      </FormGroup>
400	
401	      <FormGroup
402	        label={t('Object tags')}
403	        fieldId="object-tags"
404	        className="pf-v6-u-mb-lg"
405	      >
406	        <TextContent className="pf-v6-u-mb-sm">
407	          <Text component={TextVariants.small}>
408	            {t('An object tag is a label that is assigned to an S3 object.')}
409	          </Text>
410	        </TextContent>
411	        <ObjectTagsFilter state={state} dispatch={dispatch} />
412	        {invalidFilters && (
413	          <Alert
414	            variant={AlertVariant.danger}
415	            isInline
416	            isPlain
417	            title={t('You must specify an object tag or another filter.')}
418	            className="s3-lifecycle-validation--font-weight"
419	          />
420	        )}
421	      </FormGroup>
422	
423	      <FormGroup label={t('Object size')} fieldId="object-size">
424	        <TextContent className="pf-v6-u-mb-sm">
425	          <Text component={TextVariants.small}>
426	            {t('Set criteria for filtering objects based on their size.')}
427	          </Text>
428	        </TextContent>
429	        <ObjectSizeFilter state={state} dispatch={dispatch} />
430	        {invalidFilters && (
431	          <Alert
432	            variant={AlertVariant.danger}
433	            isInline
434	            isPlain
435	            title={t('You must specify an object size or another filter.')}
436	            className="s3-lifecycle-validation--font-weight"
437	          />
438	        )}
439	      </FormGroup>
440	      <Divider className="pf-v6-u-my-md" />
441	    </>
442	  );
443	};
