445	export const GeneralConfigAndFilters: React.FC<
446	  StateAndDispatchProps & {
447	    existingRules: GetBucketLifecycleConfigurationCommandOutput;
448	    isEdit?: boolean;
449	    editingRuleName?: string;
450	  }
451	> = ({ state, dispatch, existingRules, isEdit, editingRuleName }) => {
452	  const { t } = useCustomTranslation();
453	
454	  const [invalidName, emptyName, alreadyUsedName, exceedingLengthName] =
455	    state.triggerInlineValidations
456	      ? isInvalidName(state, existingRules, isEdit, editingRuleName)
457	      : [];
458	
459	  return (
460	    <>
461	      <TextContent className="pf-v6-u-mb-lg">
462	        <Text component={TextVariants.h2}>{t('General configuration')}</Text>
463	      </TextContent>
464	
465	      <FormGroup
466	        label={t('Lifecycle rule name')}
467	        fieldId="name"
468	        className="pf-v6-u-mb-lg"
469	      >
470	        <TextInput
471	          id="name"
472	          value={state.name}
473	          onChange={(_e, value) =>
474	            dispatch({ type: RuleActionType.RULE_NAME, payload: value })
475	          }
476	          placeholder={t('Enter a valid rule name')}
477	          className="pf-v6-u-w-50"
478	          validated={
479	            invalidName ? ValidatedOptions.error : ValidatedOptions.default
480	          }
481	        />
482	        {invalidName && (
483	          <FormHelperText>
484	            <HelperText>
485	              <HelperTextItem variant={ValidatedOptions.error}>
486	                {emptyName && t('A rule name is required.')}
487	                {alreadyUsedName &&
488	                  t(
489	                    'A rule with this name already exists. Type a different name.'
490	                  )}
491	                {exceedingLengthName && t('No more than 255 characters')}
492	              </HelperTextItem>
493	            </HelperText>
494	          </FormHelperText>
495	        )}
496	      </FormGroup>
497	
498	      <FormGroup label={t('Rule scope')} fieldId="scope">
499	        <span className="pf-v6-u-display-flex pf-v6-u-flex-direction-row">
500	          <Radio
501	            label={t('Targeted')}
502	            description={t(
503	              'Applies to a specific subset of objects within a bucket, based on defined criteria. Allows for more granular control over which objects the rule targets.'
504	            )}
505	            name={RADIO_GROUP_NAME}
506	            value={RuleScope.TARGETED}
507	            isChecked={state.scope === RuleScope.TARGETED}
508	            onChange={(event) =>
509	              dispatch({
510	                type: RuleActionType.RULE_SCOPE,
511	                payload: (event.target as HTMLInputElement).value as RuleScope,
512	              })
513	            }
514	            id={`scope-${RuleScope.TARGETED}`}
515	            className="pf-v6-u-mr-md pf-v6-u-w-50"
516	          />
517	          <Radio
518	            label={t('Global (Bucket-wide)')}
519	            description={t(
520	              'Applies to all objects in the bucket without any filters. Uses the same lifecycle action for every object in the bucket.'
521	            )}
522	            name={RADIO_GROUP_NAME}
523	            value={RuleScope.GLOBAL}
524	            isChecked={state.scope === RuleScope.GLOBAL}
525	            onChange={(event) =>
526	              dispatch({
527	                type: RuleActionType.RULE_SCOPE,
528	                payload: (event.target as HTMLInputElement).value as RuleScope,
529	              })
530	            }
531	            id={`scope-${RuleScope.GLOBAL}`}
532	            className="pf-v6-u-ml-md pf-v6-u-w-50"
533	          />
534	        </span>
535	      </FormGroup>
536	
537	      {state.scope === RuleScope.GLOBAL && (
538	        <Alert
539	          title={t('Global rule scope selected')}
540	          variant={AlertVariant.info}
541	          className="pf-v6-u-mt-md"
542	          isInline
543	        >
544	          {t(
545	            'You have selected to apply this lifecycle rule to all objects in the bucket. This may impact objects that do not require the specified expirations. If your bucket contains a mix of object types, consider using filters like prefixes or tags to target specific objects.'
546	          )}
547	        </Alert>
548	      )}
549	      <Divider className="pf-v6-u-my-md" />
550	      {state.scope === RuleScope.TARGETED && (
551	        <ConditionalFilters state={state} dispatch={dispatch} />
552	      )}
553	    </>
554	  );
555	};

